var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"시설의 상황은 어떤가요?","JPN":"施設の状況はどうですか？","ENG":"What's the SITREP on the facility?","TWN":"設施的情況怎麼樣？"},"stage":{"bg":"HELI_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"비전투원은 대피를 마친 상태지만, 패닉룸을 제외한 시설 내부는 침식체에게 완전히 점거되었습니다.","JPN":"非戦闘員は避難しましたが、パニックルーム以外の施設内部は侵食体に占拠されました。","ENG":"The noncombatants have been evacuated, but the interior has been overrun by C.O.s, save for the panic room.","TWN":"非戰鬥人員已經撤離了，除避難屋以外的設施內部，已經完全被侵蝕體佔領了。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"현재로선...... 탈출은 고사하고 여기서 계속 버티는 것도 녹록치 않은 상황입니다.","JPN":"現在の状況では……脱出はおろか、ここで耐えるのも容易ではありません。","ENG":"As of now... it'll be a challenge to hold our ground here, let alone escape.","TWN":"現在……別說逃跑了，連繼續堅守這裡都很不容易。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠습니다. 곧 도착할 테니 현장에서 뵙죠.","JPN":"わかりました。もうじき到着するので、現場で会いましょう。","ENG":"Understood. I'll be there shortly. See you soon.","TWN":"我知道了。我馬上就到，現場見吧。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT1_NPC_NULL_NULL","text":{"KOREA":"예. 부탁드리겠습니다, 기관장님.","JPN":"はい。よろしくお願いします、機関長。","ENG":"Roger that. We can't wait to see you, Chief.","TWN":"是，拜託您了。機關長。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT1_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"하 참...... 여긴 무슨 놈의 시설이 툭하면 사고가 터진대?","JPN":"はあ、ったく……この施設、なんでこんなに事故が起きるんだ？","ENG":"Bollocks... Why's this facility involved in some kind of mess all the time?","TWN":"哈啊，真是的……這是什麼鬼設施，怎麼動不動就出事？"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"지은 지도 오래 된 것 같던데, 깔끔하게 새로 만들어서 옮기는 게 낫지 않냐?","JPN":"かなり古いし、別の場所に建て替えた方がいい気がするんだがな。","ENG":"It seems to be pretty old too. Can't you just build a new one elsewhere?","TWN":"好像建立很久了，新建一個乾淨堅固的搬過去不是更好嘛？"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래요. 당신의 짧은 생각대로 클리포트의 마왕을 동네 창고에 대충 가둬 둘 수 있으면 참 좋겠네요.","JPN":"そうですね。あなたのバカな考えのとおり、\\nクリフォトの魔王を街の倉庫にでも閉じ込められるといいですね。","ENG":"Sure. I bet it'll be a brilliant idea to just keep the Demon Lord of Qliphoth locked up in a neighborhood storage room. You're a genius.","TWN":"是啊，依照你那膚淺的想法，能用村裡的倉庫關住逆卡巴拉魔王的話，真是太好了呢。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기관의 격리시설은 오래 전 구 관리국의 기술을 빌려 만든 곳이에요.","JPN":"機関の隔離施設は昔、旧管理局の技術で作られたものです。","ENG":"Our quarantine facility was built using the Old Administration's technology.","TWN":"機關的隔離設施，是很久以前借助舊管理局的技術建成的。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"지금 이 격리시설을 다시 만들 수 있는 기술은 어디에도 없습니다.","JPN":"この隔離施設を作る技術は、今現在どこにも存在しません。","ENG":"Which means the technology to rebuild this facility currently does not exist.","TWN":"現在根本沒有可以重建這種隔離設施的技術。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"완전히 망가지기 전에 가능한 한 최선을 다해 수리해서 쓸 뿐이죠.","JPN":"完全に崩壊する前に、できる限り最善を尽くして修理するしかないんです。","ENG":"All we can do is keep it repaired to the best of our ability until it's no longer usable.","TWN":"我們只能在徹底毀壞之前，盡全力地維修來延長使用。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 지금은 기관원들의 생명이 최우선입니다.","JPN":"ですが、今は機関員の命が最優先です。","ENG":"But for now, the lives of our agents take utmost priority.","TWN":"可是現在機關人員的性命最重要。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"모건과 페리어는 다른 임무로 자리를 비운 상태예요. 우리 둘이서 해결해야 합니다.","JPN":"モーガンとフェリエーは、他の任務で不在です。\\n私たち二人で解決するしかありませんわ。","ENG":"Morgan and Ferrier are currently away on another mission. We'll have to sort this out with just the two of us.","TWN":"摩根和佩里出去執行其他任務了，必須靠我們兩個人解決。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"핫, 좋아. 그동안의 성과를 똑똑히 보여 주지.","JPN":"はっ、いいぜ。今までの成果を見せてやる。","ENG":"Lovely, then. I'll show you how much I've been improving.","TWN":"哈，好啊。正好讓妳看看我在這段時間取得的成果。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"훈련 성적은 눈 뜨고 못 봐줄 지경이라던데 자신감 하나는 대단하군요.","JPN":"訓練の成績はズタボロだと伺ったのですが、自信満々ですわね。","ENG":"You sure sound confident, considering how disastrous your training scores are.","TWN":"聽說你的訓練成績差得讓人看不下去，你自己倒是很有自信啊。"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"야, 애초에 훈련 내용 자체가 말도 안 되는 것들이었잖아?","JPN":"おい、そもそも訓練の内容が普通じゃなかっただろ！","ENG":"Oh, come on. The training regimen was absolutely bonkers anyway!","TWN":"喂，當時的訓練內容本身就很不像話好嗎？"},"stage":{"bg":"HELI_NIGHT","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};